<script setup lang="ts">
const supabase = useSupabaseClient<any>()
const context = ref<any>(null), loading = ref(true), message = ref('')
const member = reactive({ email: '', role: 'member' })
const provider = reactive({ provider: 'github', client_id: '', client_secret: '' })
const isAdmin = computed(() => ['owner', 'admin'].includes(context.value?.role))
async function authed<T>(url: string, options: any = {}) { const { data: { session } } = await supabase.auth.getSession(); return $fetch<T>(url, { ...options, headers: { ...(options.headers || {}), ...(session?.access_token ? { authorization: `Bearer ${session.access_token}` } : {}) } }) }
async function load() { loading.value = true; try { context.value = await authed('/api/adaptive/context') } finally { loading.value = false } }
async function addMember() { message.value = ''; try { const result: any = await authed('/api/adaptive/members', { method: 'POST', body: member }); message.value = `${result.member.email} joined as ${result.member.role} and inherited passport v${result.member.inherited_passport_version}.`; member.email = '' } catch (e: any) { message.value = e?.data?.message || e?.message || 'Unable to add member.' } }
async function saveProvider() { message.value = ''; try { await authed('/api/connectors/admin/provider-config', { method: 'POST', body: provider }); message.value = `${provider.provider} is now delegated to organization members.`; provider.client_id = ''; provider.client_secret = ''; await load() } catch (e: any) { message.value = e?.data?.message || e?.message || 'Unable to save provider configuration.' } }
async function replay(step: any) { const result: any = await authed('/api/adaptive/onboarding/replay', { method: 'POST', body: { step_id: step.id } }); await navigateTo(result.route) }
function status(step: any) { return context.value?.onboarding?.find((item: any) => item.step_id === step.id)?.status || 'available' }
onMounted(load)
</script>
<template><section class="mt-5 rounded-xl border bg-white p-4"><div class="flex flex-wrap items-start justify-between gap-3"><div><div class="text-[10px] font-semibold uppercase tracking-[.14em] text-purple-600">Organizational capability passport</div><h2 class="mt-1 text-sm font-semibold">{{ context?.organization?.name || 'Organization' }}</h2><p class="mt-1 text-xs text-gray-500">Members inherit approved connectors, policies, permissions, objectives, and the same replayable training path.</p></div><span v-if="context" class="rounded-full bg-purple-50 px-2 py-1 text-[10px] text-purple-700">{{ context.role }} · passport v{{ context.passport?.version }} · {{ context.member_count }} member{{ context.member_count === 1 ? '' : 's' }}</span></div><div v-if="loading" class="mt-3 text-xs text-gray-400">Loading organizational context…</div><template v-else-if="context"><div class="mt-4 grid gap-3 lg:grid-cols-3"><article v-for="step in context.passport?.training_path || []" :key="step.id" class="rounded-lg border p-3"><div class="flex items-center justify-between"><span class="text-xs font-medium">{{ step.label }}</span><span class="text-[9px]" :class="status(step) === 'completed' ? 'text-emerald-600' : 'text-gray-400'">{{ status(step) }}</span></div><button class="mt-2 text-[10px] text-blue-600" @click="replay(step)">Open or replay →</button></article></div><div v-if="isAdmin" class="mt-4 grid gap-4 border-t pt-4 lg:grid-cols-2"><form @submit.prevent="addMember"><h3 class="text-xs font-semibold">Add an existing Orchestrator user</h3><p class="mt-1 text-[10px] text-gray-500">Their role inherits this passport; familiar navigation remains unchanged.</p><div class="mt-2 flex gap-2"><input v-model="member.email" type="email" required placeholder="person@example.com" class="min-w-0 flex-1 rounded-lg border px-3 py-2 text-xs"><select v-model="member.role" class="rounded-lg border px-2 text-xs"><option value="member">Member</option><option value="operator">Operator</option><option value="reviewer">Reviewer</option><option value="engineer">Engineer</option><option value="analyst">Analyst</option><option value="admin">Admin</option></select><button class="rounded-lg bg-gray-900 px-3 text-xs text-white">Add</button></div></form><form @submit.prevent="saveProvider"><h3 class="text-xs font-semibold">Delegate an OAuth provider</h3><p class="mt-1 text-[10px] text-gray-500">Administrators configure the client once; members only grant account consent.</p><div class="mt-2 grid grid-cols-2 gap-2"><select v-model="provider.provider" class="rounded-lg border px-2 py-2 text-xs"><option v-for="item in ['google','microsoft','github','slack','atlassian','notion']" :key="item">{{ item }}</option></select><input v-model="provider.client_id" required autocomplete="off" placeholder="Client ID" class="rounded-lg border px-3 py-2 text-xs"><input v-model="provider.client_secret" type="password" autocomplete="new-password" placeholder="Client secret (blank retains current)" class="col-span-2 rounded-lg border px-3 py-2 text-xs"><button class="col-span-2 rounded-lg bg-gray-900 px-3 py-2 text-xs text-white">Save delegated provider</button></div></form></div></template><p v-if="message" class="mt-3 rounded-lg bg-gray-50 p-2 text-xs text-gray-600">{{ message }}</p></section></template>
